VALUES
  ('social-worker-moex-07440', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關健康照顧社會工作（health care social work）的描述，何者錯誤？', '["管理式照顧（managed care）方案在1900年代出現後，社會工作在健康照顧領域中日漸重要，尤其是 在醫療糾紛的服務中", "健康照顧社會工作的重要歷史發展事件之一，就是1973年在美國通過的健康維護組織法案（HMO）", "協助評估案主心理和環境的優缺點，是社會工作者在健康照顧中的角色之一", "健康照顧社會工作的特色之一就是需要進行或參與任何研究，以確保實務工作的知識基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07441', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關社會工作對身心障礙者檢視身體障礙觀點的描述，何者錯誤？', '["社會心理學觀點，整合社會和情感層次，將職業、興趣、階級、性別和文化等社會因素都納入考量", "社會模型，著重於找出身心障礙者在社會上立足的位置", "心理模型，關心如何協助身心障礙者面對他人對其損傷的評估", "醫療模型，焦點在於個體的病變異常（pathology）上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07442', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Shonfeld-ringel（2001）指出跨越族群與文化的社會工作處遇，應著重社工者與案主的關係建立，其中有 一項技巧是進入案主的主觀世界，瞭解其非口語表達內容，以形塑有效的工作關係，請問該項實務工作 技巧是：', '["倡導（advocate）", "案主自決（self-determination）", "口語溝通（communication）", "使用自我（the use of self）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07443', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「社會工作者協助被安置的兒童適應寄養家庭」，此項服務符合那一項社會工作的基本功能？', '["重建", "提供資源", "預防", "發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07444', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Skidmore & Thackeray（1994）認為社會工作專業具有一些重要的特質，下列何者不屬於前述的特質？', '["強調家庭對個人及社會的重要性", "社會工作者與案主關係的建立是助人過程中重要的一環", "社會工作者需要運用社區資源，來解決人們的問題", "社會工作不傾向運用精神病理、心理治療的方法，來瞭解與分析人類行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07445', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作許多實務領域中，社會工作者皆須與其他專業形成團隊（team），運用團隊來提供適切的服 務，下列何者不是社會工作者在團隊中應扮演的角色？', '["指導者", "協調者", "整合者", "催化劑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07446', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的「社會」部分，是強調什麼，下列何者為錯誤？', '["社會互動的壓力", "社會流行的趨勢", "社會功能的失調", "社會關係的瞭解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07447', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當社會工作者首次進入某個鄰里社區，與社區居民共同工作來造成改變時，他會先建構出該地區的資產 地圖，指出社區內各項資源與各個居民的能力。上述社會工作者運用何種理論觀點來進行社區工作？', '["充權觀點（empowerment perspective）", "優勢觀點（strengths perspective）", "生態系統觀點（ecological systems perspective）", "任務中心取向（task-centered apporoach）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07448', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於風險評估與管理的要點，何者為錯誤？', '["風險的考量需視工作性質和社會工作者任職的機構而定", "風險決策必須要能經得起辯護的考驗", "社會工作者面臨「案主造成的」及「案主遭受的」二大類型之風險", "風險管理的目的在於消除風險，保證防範風險的發生，以避免案主在風險中的傷害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07449', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關「充權」理論的敘述，何者為錯誤？', '["充權在社會工作領域中，代表的是協助案主在其生活歷程中獲得力量與權力", "充權主要的焦點在於消除壓迫案主之環境因素，而非案主個人能力的提升", "充權的引導原則中，其中一種方式便是將重點放在檢視案主的優勢方面", "在充權的過程中，案主必須先相信自己有能力為自己做某些事情，而後才能為自己的生活及生活以外 的事件，增加主導與控制權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
